from dataclasses import dataclassfrom criresviz.database.loader import load_settings_database@dataclass(slots=True)class CRIRESSetting:    name: str    band: str    reference_wavelength: float    @classmethod    def from_name(cls, name: str):        """        Create a CRIRESSetting from its setting name.        Parameters        ----------        name : str            CRIRES+ setting name (e.g. "M4368").        Returns        -------        CRIRESSetting        """        database = load_settings_database()        try:            info = database[name]        except KeyError as exc:            raise ValueError(                f"Unknown CRIRES+ setting '{name}'."            ) from exc        return cls(            name=name,            band=info["band"],            reference_wavelength=info["reference_wavelength"]        )        def __str__(self):            return (            "CRIRES+ Setting\n"            "──────────────────────────────\n"            f"Name:                 {self.name}\n"            f"Band:                 {self.band}\n"            f"Reference wavelength:   {self.reference_wavelength:.3f} μm"        )